  insert into public.events (slug, title, subtitle, season, is_published, theme)
  values (
    'leadership-youth-2026-27',
    'Youth Leadership Roles · 2026–2027',
    'Lead your patrol. Trail Life MN-9871 leadership signup for boys.',
