    youth_id,
    0,
    'Leadership',
    'Patrol Leader',
    'Lead your patrol. Set the tone every Thursday.',
    'The Patrol Leader is the senior youth voice in his patrol. He opens meetings, assigns tasks, keeps order, and leads his guys through the weekly agenda. He is the first call when something goes sideways and the first to model servant leadership. This is the highest youth leadership role in the troop.',
    2,
    true,
    '"Let no one despise you for your youth, but set the believers an example." — 1 Timothy 4:12',
    '~3 hrs/week (meetings + prep)',
    'Navigator Trail Master',
    '["His patrol runs smoothly even when adults step back","Every guy in the patrol knows what is happening and what is expected","He knows each boy by name and is intentional about including everyone","He shows up early, stays late, and leaves the space better than he found it"]'::jsonb,
    '["A boss who barks orders — he leads by example","The adult Trail Guide (he defers to adult leaders on safety and discipline)","Optional — he is at every meeting unless sick or pre-approved absent"]'::jsonb,
    '[]'::jsonb
    );

